class Solution:
    def climbStairs(self, n: int, costs: List[int]) -> int:
        if n == 0:
            return 0
        dp = [0] * n
        dp[0] = costs[0]
        for i in range(1, n):
            for j in range(1, min(i+1, 3)):
                dp[i] = min(dp[i], dp[i-j] + costs[i])
        return dp[n-1]

if __name__ == '__main__':
    solver = Solution()
    n, costs = map(int, input().split())
    print(solver.climbStairs(n, costs))

