class Solution {
public:
    int climbStairs(int n, vector<int>& costs) {
        if (n == 0) return 0;
        int dp[n];
        dp[0] = costs[0];
        for (int i = 1; i < n; i++) {
            for (int j = 1; j <= min(i+1, 3); j++) {
                dp[i] = min(dp[i], dp[i-j] + costs[i]);
            }
        }
        return dp[n-1];
    }
};

int main() {
    Solution solver;
    int n; cin >> n;
    vector<int> costs(n);
    for (int i = 0; i < n; i++) cin >> costs[i];
    cout << solver.climbStairs(n, costs) << endl;
    return 0;
}
